insert into public.stock_movements(
  id,
  movement_type,
  box_id,
  owner_id,
  product_id,
  qty,
  before_qty,
  after_qty,
  scanned_barcode,
  reason,
  notes,
  created_at
)
select
  source_items.movement_id::uuid,
  'in',
  boxes.id,
  boxes.owner_id,
  products.id,
  source_items.qty::numeric,
  0,
  source_items.qty::numeric,
  boxes.barcode_value,
  'Import data client GudangKu',
  source_items.label,
  source_items.created_at::timestamptz
from source_items
join public.boxes on boxes.id_box = source_items.id_box
join public.products on products.sku = source_items.sku
on conflict (id) do update set
  box_id = excluded.box_id,
  owner_id = excluded.owner_id,
  product_id = excluded.product_id,
  qty = excluded.qty,
  before_qty = excluded.before_qty,
  after_qty = excluded.after_qty,
  scanned_barcode = excluded.scanned_barcode,
  reason = excluded.reason,
  notes = excluded.notes,
  created_at = excluded.created_at;

insert into public.import_batches(
  id,
  import_type,
  file_name,
  status,
  total_rows,
  success_rows,
  failed_rows,
  error_summary,
  completed_at
)
values (
  'e509cc2e-be3b-3fcc-a421-a7618aeef140',
  'client_kardus',
  'GudangKu Database - kardus.csv',
  'success',
  658,
  656,
  1,
  'Ada 1 baris CSV dengan id box yang sama tetapi isi metadata berbeda. Import memakai baris pertama untuk master box dan menyimpan semua baris di client_gudangku_kardus_raw.',
  now()
)
on conflict (id) do update set
  status = excluded.status,
  total_rows = excluded.total_rows,
  success_rows = excluded.success_rows,
  failed_rows = excluded.failed_rows,
  error_summary = excluded.error_summary,
  completed_at = excluded.completed_at;

commit;
